import type {
  AuthPluginComponents,
  AuthPlugin as AuthPluginPrimitive
} from "@better-auth-ui/react"

declare module "@better-auth-ui/core" {
  /** Widens `useAuth().plugins` to the shadcn-typed `AuthPlugin`. */
  interface AuthPluginRegister {
    shadcn: AuthPlugin
  }
}

/** Props the shadcn `<Auth>` router spreads onto plugin-contributed auth views. */
export type AuthViewProps = {
  className?: string
  socialLayout?: "auto" | "horizontal" | "vertical" | "grid"
  socialPosition?: "top" | "bottom"
}

/** Props the shadcn `<Settings>` router spreads onto plugin-contributed settings views. */
export type SettingsViewProps = {
  className?: string
}

/** Shadcn plugin type. Plugin authors import this from `@/lib/auth-plugin`. */
export type AuthPlugin = AuthPluginPrimitive<
  AuthPluginComponents,
  AuthViewProps,
  SettingsViewProps
>

import { createAuthPlugin } from "@better-auth-ui/core"
import {
  themePlugin as coreThemePlugin,
  type ThemeLocalization
} from "@better-auth-ui/core/plugins"

import { Appearance } from "@/components/theme/appearance"
import { ThemeToggleItem } from "@/components/theme/theme-toggle-item"

/**
 * Hook shape compatible with `next-themes`' `useTheme` and similar APIs. The
 * hook is invoked inside the plugin factory so consumers can register the
 * plugin in the same component as their `<ThemeProvider>` without an extra
 * inner component.
 */
export type UseThemeHook = () => {
  theme?: string
  setTheme: (theme: string) => void
  themes?: string[]
}

type BaseThemeOptions = {
  /**
   * Override the plugin's default localization strings.
   * @remarks `ThemeLocalization`
   */
  localization?: Partial<ThemeLocalization>
  /**
   * Initial theme value.
   */
  theme?: string
  /**
   * Available theme options.
   * @default ["system", "light", "dark"]
   */
  themes?: string[]
}

export type ThemePluginOptions = BaseThemeOptions &
  (
    | {
        /**
         * A theme hook (e.g. next-themes' `useTheme`) called inside the
         * plugin factory to read live theme state. When provided,
         * `setTheme` is not required.
         */
        useTheme: UseThemeHook
        setTheme?: never
      }
    | {
        /** Function to set the theme. */
        setTheme: (theme: string) => void
        useTheme?: never
      }
  )

export const themePlugin = createAuthPlugin(
  coreThemePlugin.id,
  ({ useTheme, ...rest }: ThemePluginOptions) => {
    // No-op `setTheme` baseline keeps core's required option satisfied when
    // the consumer is passing a hook (and therefore omitting `setTheme`).
    const base = coreThemePlugin({ setTheme: () => {}, ...rest })
    return {
      ...base,
      // Slot components always call `plugin.useTheme()` — invoking the hook
      // inside their render keeps it in scope of any `<ThemeProvider>` the
      // consumer mounts. When the consumer passed static config instead, we
      // synthesize a stub that returns those same values.
      useTheme:
        useTheme ??
        (() => ({
          theme: base.theme,
          setTheme: base.setTheme,
          themes: base.themes
        })),
      userMenuItems: [ThemeToggleItem],
      accountCards: [Appearance]
    }
  }
)

"use client"

import { useAuthPlugin } from "@better-auth-ui/react"
import { Monitor, Moon, Sun } from "lucide-react"

import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { themePlugin } from "@/lib/theme/theme-plugin"

/**
 * Theme toggle dropdown item used inside `UserButton`. Callers are responsible
 * for ensuring theming is configured before rendering this component.
 */
export function ThemeToggleItem() {
  const { useTheme, localization } = useAuthPlugin(themePlugin)
  const { theme, setTheme, themes = [] } = useTheme()

  return (
    <div
      className="py-1.5 px-2 flex items-center justify-between cursor-default hover:bg-transparent!"
      onSelect={(e) => e.preventDefault()}
    >
      <span className="text-sm">{localization.theme}</span>

      <Tabs value={theme} onValueChange={setTheme}>
        <TabsList className="h-6!">
          {themes.includes("system") && (
            <TabsTrigger
              value="system"
              className="size-5 p-0"
              aria-label={localization.system}
            >
              <Monitor className="size-3" />
            </TabsTrigger>
          )}
          {themes.includes("light") && (
            <TabsTrigger
              value="light"
              className="size-5 p-0"
              aria-label={localization.light}
            >
              <Sun className="size-3" />
            </TabsTrigger>
          )}
          {themes.includes("dark") && (
            <TabsTrigger
              value="dark"
              className="size-5 p-0"
              aria-label={localization.dark}
            >
              <Moon className="size-3" />
            </TabsTrigger>
          )}
        </TabsList>
      </Tabs>
    </div>
  )
}
